// Datos del trigger
const triggerData = $('Recibir Pedido').first().json;
const corrData = $('Obtener Correlativo').first().json;

const items = triggerData.items;
const codCliente = triggerData.cod_cliente;
const codLen = triggerData.cod_cliente_len || 4;
const carpeta = triggerData.carpeta_pedidos;
const correlativo = corrData.correlativo;

const codPadded = codCliente.toString().padStart(codLen, '0');
const corrPadded = correlativo.toString().padStart(6, '0');
const fileName = `${codPadded}P${corrPadded}.txt`;

const lines = items.map(item => {
  const precio = parseFloat(item.precio_unitario || 0).toFixed(2);
  return `${item.codigo_producto};${item.descripcion};${item.cantidad};${precio}`;
});
const fileContent = lines.join('\n');

const totalItems = items.length;
const totalUnidades = items.reduce((s, i) => s + (parseFloat(i.cantidad) || 0), 0);
const totalMonto = items.reduce((s, i) => s + ((parseFloat(i.cantidad) || 0) * (parseFloat(i.precio_unitario) || 0)), 0);

return [{
  json: {
    fileName,
    fileContent,
    fullPath: `${carpeta}${fileName}`,
    correlativo,
    totalItems,
    totalUnidades: totalUnidades.toFixed(2),
    totalMonto: totalMonto.toFixed(2),
    drogueria_code: triggerData.drogueria_code,
    cod_cliente: codCliente,
    ftp_credential_name: triggerData.ftp_credential_name
  }
}];
